	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(m int64, n int64, waitCost [][]int64) int64 {
	if m == 1 && n == 1 {
		return 1
	}

	mInt := int(m)
	nInt := int(n)

	dp := make([][][]int64, mInt)
	for i := 0; i < mInt; i++ {
		dp[i] = make([][]int64, nInt)
		for j := 0; j < nInt; j++ {
			dp[i][j] = make([]int64, 2)
			for k := 0; k < 2; k++ {
				dp[i][j][k] = math.MaxInt64
			}
		}
	}

	pq := &PriorityQueue{}
	heap.Init(pq)
	dp[0][0][1] = 1
	heap.Push(pq, &Item{cost: 1, i: 0, j: 0, parity: 1})

	directions := [][2]int{{1, 0}, {0, 1}}

	for pq.Len() > 0 {
		item := heap.Pop(pq).(*Item)
		currentCost := item.cost
		i := item.i
		j := item.j
		parity := item.parity

		if i == mInt-1 && j == nInt-1 {
			return currentCost
		}

		if currentCost > dp[i][j][parity] {
			continue
		}

		if parity == 1 {
			for _, dir := range directions {
				nI := i + dir[0]
				nJ := j + dir[1]
				if nI >= 0 && nI < mInt && nJ >= 0 && nJ < nInt {
					entryCost := int64((nI + 1) * (nJ + 1))
					newCost := currentCost + entryCost
					newParity := 0
					if newCost < dp[nI][nJ][newParity] {
						dp[nI][nJ][newParity] = newCost
						heap.Push(pq, &Item{cost: newCost, i: nI, j: nJ, parity: newParity})
					}
				}
			}
		} else {
			waitCostVal := int64(waitCost[i][j])
			newCost := currentCost + waitCostVal
			newParity := 1
			if newCost < dp[i][j][newParity] {
				dp[i][j][newParity] = newCost
				heap.Push(pq, &Item{cost: newCost, i: i, j: j, parity: newParity})
			}
		}
	}

	return -1
}
